-- =============================================================================
-- Migration: Schema Evolution Phase 1
-- Description: Trades, Project Outcomes, Type Orders, BOM Action Requests,
--              and related junction tables + ALTER existing tables
-- Date: 2026-03-04
-- =============================================================================

-- =============================================================================
-- 1A. trades table (NEW)
-- =============================================================================
CREATE TABLE IF NOT EXISTS public.trades (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    code text NOT NULL UNIQUE,
    name text NOT NULL,
    description text,
    icon text,
    color text,
    display_order integer DEFAULT 0,
    is_active boolean NOT NULL DEFAULT true,
    scope text NOT NULL DEFAULT 'system',
    organization_id uuid REFERENCES public.organizations(id) ON DELETE CASCADE,
    parent_trade_id uuid REFERENCES public.trades(id) ON DELETE SET NULL,
    created_at timestamptz NOT NULL DEFAULT now(),
    updated_at timestamptz NOT NULL DEFAULT now(),
    CONSTRAINT trades_scope_check CHECK (scope IN ('system', 'company')),
    CONSTRAINT valid_system_trade CHECK ((scope = 'system' AND organization_id IS NULL) OR scope <> 'system'),
    CONSTRAINT valid_company_trade CHECK ((scope = 'company' AND organization_id IS NOT NULL) OR scope <> 'company')
);

-- RLS for trades
ALTER TABLE public.trades ENABLE ROW LEVEL SECURITY;

CREATE POLICY "trades_select_system" ON public.trades FOR SELECT
    USING (scope = 'system');

CREATE POLICY "trades_select_company" ON public.trades FOR SELECT
    USING (scope = 'company' AND organization_id = current_user_organization_id());

CREATE POLICY "trades_insert_company" ON public.trades FOR INSERT
    WITH CHECK (scope = 'company' AND organization_id = current_user_organization_id());

CREATE POLICY "trades_update_company" ON public.trades FOR UPDATE
    USING (scope = 'company' AND organization_id = current_user_organization_id());

CREATE POLICY "trades_delete_company" ON public.trades FOR DELETE
    USING (scope = 'company' AND organization_id = current_user_organization_id());

-- Indexes for trades
CREATE INDEX IF NOT EXISTS idx_trades_code ON public.trades(code);
CREATE INDEX IF NOT EXISTS idx_trades_scope ON public.trades(scope);
CREATE INDEX IF NOT EXISTS idx_trades_organization_id ON public.trades(organization_id);

-- Updated_at trigger for trades
DO $$ BEGIN
    CREATE TRIGGER update_trades_updated_at
        BEFORE UPDATE ON public.trades
        FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

