CREATE TABLE IF NOT EXISTS public.bom_action_requests (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    project_id uuid NOT NULL REFERENCES public.wo_projects(id) ON DELETE CASCADE,
