        FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- =============================================================================
-- 1I. ALTER work_order_templates — add new columns
-- =============================================================================
ALTER TABLE public.work_order_templates
    ADD COLUMN IF NOT EXISTS trade_id uuid REFERENCES public.trades(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS sop_id uuid REFERENCES public.sops(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS outcome_id uuid REFERENCES public.project_outcomes(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS inheritance_depth integer DEFAULT 0,
    ADD COLUMN IF NOT EXISTS source_template_id uuid REFERENCES public.work_order_templates(id) ON DELETE SET NULL;

-- =============================================================================
-- 1J. ALTER work_orders — add new columns
-- =============================================================================
ALTER TABLE public.work_orders
    ADD COLUMN IF NOT EXISTS trade_id uuid REFERENCES public.trades(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS bom_action_request_id uuid REFERENCES public.bom_action_requests(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS type_order_id uuid REFERENCES public.type_orders(id) ON DELETE SET NULL;

-- =============================================================================
-- 1K. ALTER sops — add new columns
-- =============================================================================
ALTER TABLE public.sops
    ADD COLUMN IF NOT EXISTS trade_id uuid REFERENCES public.trades(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS scope text DEFAULT 'system',
    ADD COLUMN IF NOT EXISTS outcome_id uuid REFERENCES public.project_outcomes(id) ON DELETE SET NULL;

-- =============================================================================
-- 1L. ALTER units — add type_order_id
-- =============================================================================
ALTER TABLE public.units
    ADD COLUMN IF NOT EXISTS type_order_id uuid REFERENCES public.type_orders(id) ON DELETE SET NULL;

-- =============================================================================
-- 1M. ALTER wo_projects — add outcome_id
-- =============================================================================
ALTER TABLE public.wo_projects
    ADD COLUMN IF NOT EXISTS outcome_id uuid REFERENCES public.project_outcomes(id) ON DELETE SET NULL;

-- =============================================================================
-- 1N. Scope rename: 'app' -> 'system'
-- =============================================================================

-- Step 1: Drop ALL scope-related constraints FIRST (before updating data)
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS work_order_templates_scope_check;
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS valid_app_scope;
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS valid_system_scope;
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS valid_company_scope;
ALTER TABLE public.work_order_templates DROP CONSTRAINT IF EXISTS valid_project_scope;

-- Step 2: Update data
UPDATE public.work_order_templates SET scope = 'system' WHERE scope = 'app';

-- Step 3: Re-add constraints with new scope values
ALTER TABLE public.work_order_templates ADD CONSTRAINT work_order_templates_scope_check
    CHECK (scope IN ('system', 'company', 'project'));
ALTER TABLE public.work_order_templates ADD CONSTRAINT valid_system_scope
    CHECK ((scope = 'system' AND organization_id IS NULL AND project_id IS NULL) OR scope <> 'system');
ALTER TABLE public.work_order_templates ADD CONSTRAINT valid_company_scope
    CHECK ((scope = 'company' AND organization_id IS NOT NULL AND project_id IS NULL) OR scope <> 'company');
ALTER TABLE public.work_order_templates ADD CONSTRAINT valid_project_scope
    CHECK ((scope = 'project' AND organization_id IS NOT NULL AND project_id IS NOT NULL) OR scope <> 'project');

-- Same for template_libraries
ALTER TABLE public.template_libraries DROP CONSTRAINT IF EXISTS template_libraries_scope_check;
ALTER TABLE public.template_libraries DROP CONSTRAINT IF EXISTS valid_app_library;
ALTER TABLE public.template_libraries DROP CONSTRAINT IF EXISTS valid_system_library;
ALTER TABLE public.template_libraries DROP CONSTRAINT IF EXISTS valid_company_library;

UPDATE public.template_libraries SET scope = 'system' WHERE scope = 'app';

ALTER TABLE public.template_libraries ADD CONSTRAINT template_libraries_scope_check
    CHECK (scope IN ('system', 'company'));
ALTER TABLE public.template_libraries ADD CONSTRAINT valid_system_library
    CHECK ((scope = 'system' AND organization_id IS NULL) OR scope <> 'system');
ALTER TABLE public.template_libraries ADD CONSTRAINT valid_company_library
    CHECK ((scope = 'company' AND organization_id IS NOT NULL) OR scope <> 'company');

-- 1O. Trade name sync trigger
-- =============================================================================
CREATE OR REPLACE FUNCTION public.sync_trade_name()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.trade_id IS NOT NULL AND (TG_OP = 'INSERT' OR OLD.trade_id IS DISTINCT FROM NEW.trade_id) THEN
        SELECT name INTO NEW.trade_name FROM public.trades WHERE id = NEW.trade_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_trade_name_templates ON public.work_order_templates;
CREATE TRIGGER trg_sync_trade_name_templates
    BEFORE INSERT OR UPDATE OF trade_id ON public.work_order_templates
    FOR EACH ROW EXECUTE FUNCTION public.sync_trade_name();

DROP TRIGGER IF EXISTS trg_sync_trade_name_work_orders ON public.work_orders;
CREATE TRIGGER trg_sync_trade_name_work_orders
    BEFORE INSERT OR UPDATE OF trade_id ON public.work_orders
    FOR EACH ROW EXECUTE FUNCTION public.sync_trade_name();

-- Trade name + code sync trigger for sops
CREATE OR REPLACE FUNCTION public.sync_trade_name_and_code()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.trade_id IS NOT NULL AND (TG_OP = 'INSERT' OR OLD.trade_id IS DISTINCT FROM NEW.trade_id) THEN
        SELECT name, code INTO NEW.trade_name, NEW.trade_code FROM public.trades WHERE id = NEW.trade_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_trade_name_code_sops ON public.sops;
CREATE TRIGGER trg_sync_trade_name_code_sops
    BEFORE INSERT OR UPDATE OF trade_id ON public.sops
    FOR EACH ROW EXECUTE FUNCTION public.sync_trade_name_and_code();

-- =============================================================================
-- 1P. Updated_at triggers for all new tables (already created above inline)
-- Trades, project_outcomes, type_orders, bom_action_requests triggers
-- were created in their respective sections above.
-- =============================================================================
